targets.rawSql:
SELECT count(*) AS dlq_last_15m
FROM monitoring.dead_letter_events
WHERE ts_utc >= now() - interval '15 minutes';

SELECT
  COALESCE(EXTRACT(EPOCH FROM (now() - MAX(ts_utc))), 0) AS sec_api
FROM monitoring.api_calls;

SELECT
  COALESCE(EXTRACT(EPOCH FROM (now() - MAX(ingest_ts))), 0) AS sec_ingest
FROM public.raw_prices;
